Here's a complete MSTest approach using a mock `HttpMessageHandler` and proper async/cancellation patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // Fake handler lets you control HttpClient responses in tests
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;
        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var handler = new FakeHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnErrorStatus()
    {
        using var handler = new FakeHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.InternalServerError)));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenAlreadyCanceled()
    {
        using var handler = new FakeHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel before calling

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenCanceledDuringRequest()
    {
        using var cts = new CancellationTokenSource();

        using var handler = new FakeHandler((_, ct) =>
        {
            cts.Cancel(); // simulate mid-request cancellation
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK));
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // safety net — test itself should complete in ms
    public async Task FetchAsync_RespectsTimeout_ViaHttpClient()
    {
        using var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }
}
```

**Key patterns:**

| Technique | Why |
|---|---|
| `FakeHandler` | Avoids real HTTP; gives full control over responses |
| `CancellationTokenSource` + pre-cancel | Tests the "already canceled" path |
| Cancel inside handler | Tests mid-flight cancellation |
| `HttpClient.Timeout` | Tests timeout without slow real networks |
| `[Timeout(5000)]` | Prevents the test itself from hanging if something goes wrong |

**One gotcha:** `HttpClient.Timeout` fires its own internal `CancellationTokenSource`, so timeouts surface as `TaskCanceledException`, not `TimeoutException` (unless you're on .NET 6+ where `HttpClient` wraps it in `TaskCanceledException` with an inner `TimeoutException`).
